            color: '#f8fafc',
            border: 'none',
            borderRadius: '8px',
            cursor: isLoading || !input.trim() ? 'not-allowed' : 'pointer',
            fontSize: '13px',
            fontWeight: 600,
            transition: 'background 0.2s',
          }}
        >
          {isLoading ? '...' : '전송'}
